import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion'; // For smooth animations
import { clearAuth } from '../api';
import { 
  Menu, X, Home, MessageSquare, 
  AlertTriangle, Bell, Users, LogOut 
} from 'lucide-react';

const navItems = [
  { name: 'Home',      path: '/user/home',      icon: Home },
  { name: 'Feedback',  path: '/user/feedback',  icon: MessageSquare },
  { name: 'Complaint', path: '/user/complaint', icon: AlertTriangle },
  { name: 'Notices',   path: '/user/notices',   icon: Bell },
  { name: 'Societies', path: '/user/societies', icon: Users },
];

const Navbar = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = () => {
    clearAuth();
    navigate('/login');
  };

  return (
    <nav className="sticky top-0 z-[1000] w-full border-b border-white/10 bg-[#080e1a]/90 backdrop-blur-md">
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="flex h-16 items-center justify-between">

          {/* Logo Section */}
          <div 
            className="flex cursor-pointer items-center gap-2 group" 
            onClick={() => navigate('/user/home')}
          >
            <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-amber-500/10 text-amber-500 transition-transform group-hover:scale-110">
              <span className="text-2xl font-bold">⬡</span>
            </div>
            <span className="text-xl font-bold tracking-tight text-amber-500 font-display">
              HostelMate
            </span>
          </div>

          {/* Desktop Links */}
          <div className="hidden md:flex md:items-center md:gap-1">
            {navItems.map(({ name, path, icon: Icon }) => {
              const isActive = location.pathname === path;
              return (
                <Link
                  key={path}
                  to={path}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 
                    ${isActive 
                      ? 'bg-amber-500/10 text-amber-500 ring-1 ring-amber-500/20' 
                      : 'text-slate-400 hover:bg-white/5 hover:text-white'
                    }`}
                >
                  <Icon size={16} />
                  {name}
                </Link>
              );
            })}

            <button 
              onClick={handleLogout}
              className="ml-4 flex items-center gap-2 rounded-lg bg-red-500/10 px-4 py-2 text-sm font-medium text-red-400 border border-red-500/20 transition-all hover:bg-red-500/20 hover:text-red-300"
            >
              <LogOut size={16} />
              Logout
            </button>
          </div>

          {/* Mobile Hamburger Button */}
          <div className="flex md:hidden">
            <button
              onClick={() => setMenuOpen(!menuOpen)}
              className="inline-flex items-center justify-center rounded-lg p-2 text-amber-500 hover:bg-amber-500/10 focus:outline-none transition-colors"
            >
              {menuOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu with Animation */}
      <AnimatePresence>
        {menuOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.2, ease: "easeInOut" }}
            className="md:hidden border-t border-white/5 bg-[#0b1221] overflow-hidden"
          >
            <div className="space-y-1 px-4 pb-6 pt-4">
              {navItems.map(({ name, path, icon: Icon }) => {
                const isActive = location.pathname === path;
                return (
                  <Link
                    key={path}
                    to={path}
                    onClick={() => setMenuOpen(false)}
                    className={`flex items-center gap-3 rounded-xl px-4 py-3 text-base font-medium transition-all
                      ${isActive 
                        ? 'bg-amber-500/10 text-amber-500 ring-1 ring-amber-500/20' 
                        : 'text-slate-400 hover:bg-white/5'
                      }`}
                  >
                    <Icon size={20} />
                    {name}
                  </Link>
                );
              })}

              <div className="pt-4 mt-4 border-t border-white/5">
                <button
                  onClick={() => { handleLogout(); setMenuOpen(false); }}
                  className="flex w-full items-center gap-3 rounded-xl bg-red-500/10 px-4 py-3 text-base font-medium text-red-400 border border-red-500/20"
                >
                  <LogOut size={20} />
                  Logout
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
};

export default Navbar;
